 30→  const color = score >= 70 ? '#22c55e' : score >= 40 ? '#f59e0b' : '#ef4444';
 31→
 32→  return (
 33→    <div className="relative" style={{ width: size, height: size }}>
 34→      <svg width={size} height={size} className="transform -rotate-90">
 35→        <circle cx={size / 2} cy={size / 2} r={radius} stroke="rgba(255,255,255,0.05)" strokeWidth="8" fill="none" />
 36→        <circle cx={size / 2} cy={size / 2} r={radius} stroke={color} strokeWidth="8" fill="none"
 37→          strokeLinecap="round" strokeDasharray={circumference} strokeDashoffset={offset}
 38→          style={{ transition: 'stroke-dashoffset 1s ease-out' }} />
 39→      </svg>
 40→      <div className="absolute inset-0 flex flex-col items-center justify-center">
 41→        <span className="text-3xl font-bold text-white">{score}</span>
 42→        <span className="text-[10px] text-gray-500 uppercase tracking-wider">/100</span>
 43→      </div>
 44→    </div>
 45→  );
